class Solution:
    def makeTheIntegerZero(self, num1: int, num2: int) -> int:
        if num2 == 0:
            return 1 if num1 == 0 else -1
        if num2 > 0:
            return -1 if num1 % num2 != 0 else (num1 // num2)
        operations = 0
        while num1 != 0:
            found = False
            for i in range(60):
                if num1 - (2 * i + num2) == 0:
                    operations += 1
                    num1 = 0
                    found = True
                    break
                elif num1 - (2 * i + num2) < 0 and num1 - (2 * i + num2) % num2 == 0:
                    operations += 1
                    num1 = num1 - (2 * i + num2)
                    found = True
                    break
            if not found:
                return -1
        return operations
